const idea = $('Webhook').item.json.body.idea;
const marketOutput = $('Market Analyst Agent (ReAct)').item.json.text || '';
const researchOutput = $('Research Agent (Tool Use)').item.json.output || '';
const criticInitial = $('Critic Agent — Initial Critique').item.json.text || '';
const criticFinal = $('Critic Agent — Reflection Pass').item.json.text || '';
const finalRaw = $('Orchestrator — Final Synthesis').item.json.text || '';

// Extract market score
const marketMatch = marketOutput.match(/MARKET SCORE.*?(\d+(?:\.\d+)?)\/10/i);
const marketScore = marketMatch ? marketMatch[1] + '/10' : 'N/A';

// Extract risk score
const riskMatch = criticFinal.match(/RISK SCORE.*?(\d+(?:\.\d+)?)\/10/i);
const riskScore = riskMatch ? riskMatch[1] + '/10' : 'N/A';

return [{
  json: {
    startup_idea: idea,
    agents: {
      market_analyst: {
        agent: 'Market Analyst Agent',
        pattern: 'ReAct',
        output: marketOutput,
        score: marketScore,
        tool_trace: []
      },
      research_agent: {
        agent: 'Research Agent',
        pattern: 'Tool Use',
        output: researchOutput,
        score: 'N/A',
        tool_trace: []
      },
      critic_agent: {
        agent: 'Critic Agent',
        pattern: 'Reflection',
        initial_critique: criticInitial,
        output: criticFinal,
        score: riskScore
      }
    },
    final_report: {
      raw: finalRaw,
      market_score: marketScore,
      risk_score: riskScore
    }
  }
}];
